final:
module RefModule (
    input clk,
    input rst,
    output reg [2:0] gray
);
    reg [2:0] unused_binary;

    always @(posedge clk or posedge rst) begin
        if (rst)
            unused_binary <= 3'b000;
        else
            unused_binary <= unused_binary + 1;
    end

    always @(unused_binary) begin
        gray = unused_binary ^ (unused_binary >> 1);
    end
endmodule
